INSERT INTO tracks (id,slug,name_en,name_fr,description_en,description_fr,icon,color,sort_order) VALUES ('00000000-0000-0000-0001-000000000001','leadership','Leadership Coaching','Coaching en Leadership','Develop your leadership across 5 Pillars and 21 dimensions — from personal mastery and directional clarity to relational intelligence, team performance, and multiplication & impact.','Développez votre leadership à travers 5 Piliers et 21 dimensions — de la maîtrise personnelle à l''intelligence relationnelle, la performance d''équipe et la multiplication de l''impact.','crown','#F9250E',1);
