INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000003','00000000-0000-0000-0002-000000000001','leading-yourself-discipline-habits-character','Leading Yourself (Discipline, Habits, Character)','Leading Yourself (Discipline, Habits, Character)',3);
