INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000007','00000000-0000-0000-0002-000000000002','strategic-planning-execution','Strategic Planning & Execution','Strategic Planning & Execution',2);
