INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000003','00000000-0000-0000-0001-000000000001','relational-leadership','Relational Leadership','Relational Leadership','The Process — Culture pillar','The Process — Culture pillar',3);
