INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000004','00000000-0000-0000-0001-000000000001','performance-leadership','Performance Leadership','Performance Leadership','Execution discipline pillar','Execution discipline pillar',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000014','00000000-0000-0000-0002-000000000004','delegation','Delegation','Delegation',1);
