INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000009','00000000-0000-0000-0001-000000000002','organisational-leadership','Organisational Leadership','Organisational Leadership','Stewardship of people and resources','Stewardship of people and resources',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000035','00000000-0000-0000-0002-000000000009','vision-strategic-planning','Vision & Strategic Planning','Vision & Strategic Planning',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000141','00000000-0000-0000-0003-000000000035','I have a clear 3-5 year vision for where this ministry is heading.','J''ai une vision claire à 3-5 ans de la direction de ce ministère.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000142','00000000-0000-0000-0003-000000000035','I have communicated this vision so clearly that my leaders can repeat it.','J''ai communiqué cette vision si clairement que mes leaders peuvent la répéter.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000143','00000000-0000-0000-0003-000000000035','I have a strategic plan with measurable milestones, not just good intentions.','J''ai un plan stratégique avec des jalons mesurables, pas seulement de bonnes intentions.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000144','00000000-0000-0000-0003-000000000035','I regularly evaluate whether our activities align with our stated vision.','J''évalue régulièrement si nos activités s''alignent avec notre vision déclarée.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000036','00000000-0000-0000-0002-000000000009','team-building-volunteer-management','Team Building & Volunteer Management','Team Building & Volunteer Management',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000145','00000000-0000-0000-0003-000000000036','I recruit volunteers based on their gifts, not just their availability.','Je recrute des bénévoles en fonction de leurs dons, pas seulement de leur disponibilité.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000146','00000000-0000-0000-0003-000000000036','I invest in training and developing my ministry team regularly.','J''investis régulièrement dans la formation et le développement de mon équipe ministérielle.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000147','00000000-0000-0000-0003-000000000036','I appreciate and celebrate my volunteers, not just use them.','J''apprécie et célèbre mes bénévoles, pas seulement les utiliser.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000148','00000000-0000-0000-0003-000000000036','I have a system for onboarding, equipping, and releasing new volunteers.','J''ai un système pour intégrer, équiper et lancer de nouveaux bénévoles.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000037','00000000-0000-0000-0002-000000000009','financial-stewardship','Financial Stewardship','Financial Stewardship',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000149','00000000-0000-0000-0003-000000000037','My ministry has a transparent budget that the leadership team reviews regularly.','Mon ministère a un budget transparent que l''équipe de direction revoit régulièrement.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000150','00000000-0000-0000-0003-000000000037','I teach biblical principles of giving and stewardship to my congregation.','J''enseigne les principes bibliques du don et de l''intendance à ma congrégation.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000151','00000000-0000-0000-0003-000000000037','I personally model generosity and financial integrity.','Je modélise personnellement la générosité et l''intégrité financière.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000152','00000000-0000-0000-0003-000000000037','I ensure proper financial controls — multiple signatories, audits, reporting.','J''assure des contrôles financiers appropriés — signataires multiples, audits, rapports.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000038','00000000-0000-0000-0002-000000000009','governance-church-administration','Governance & Church Administration','Governance & Church Administration',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000153','00000000-0000-0000-0003-000000000038','My church/ministry has a clear governance structure with defined roles.','Mon église/ministère a une structure de gouvernance claire avec des rôles définis.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000154','00000000-0000-0000-0003-000000000038','I maintain proper records (membership, finances, meeting minutes).','Je maintiens des registres appropriés (membres, finances, procès-verbaux).',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000155','00000000-0000-0000-0003-000000000038','I delegate administrative tasks rather than trying to do everything myself.','Je délègue les tâches administratives plutôt que d''essayer de tout faire moi-même.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000156','00000000-0000-0000-0003-000000000038','I use technology and systems to improve ministry efficiency.','J''utilise la technologie et les systèmes pour améliorer l''efficacité du ministère.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000010','00000000-0000-0000-0001-000000000002','sustainability-multiplication','Sustainability & Multiplication','Sustainability & Multiplication','Ministry that outlives you','Ministry that outlives you',5);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000039','00000000-0000-0000-0002-000000000010','succession-planning','Succession Planning','Succession Planning',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000157','00000000-0000-0000-0003-000000000039','I am actively preparing someone to take over my role if needed.','Je prépare activement quelqu''un pour reprendre mon rôle si nécessaire.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000158','00000000-0000-0000-0003-000000000039','I share leadership responsibilities so the ministry doesn''t depend solely on me.','Je partage les responsabilités de leadership pour que le ministère ne dépende pas uniquement de moi.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000159','00000000-0000-0000-0003-000000000039','I have a documented succession plan, even if informal.','J''ai un plan de succession documenté, même informel.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000160','00000000-0000-0000-0003-000000000039','I am emotionally willing to step aside when the time is right.','Je suis émotionnellement prêt à me retirer quand le moment est venu.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000040','00000000-0000-0000-0002-000000000010','leader-development','Leader Development','Leader Development',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000161','00000000-0000-0000-0003-000000000040','I invest in developing other ministers and leaders around me.','J''investis dans le développement d''autres ministres et leaders autour de moi.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000162','00000000-0000-0000-0003-000000000040','I give emerging leaders real platforms and opportunities, not just theory.','Je donne aux leaders émergents de vraies plateformes et opportunités, pas seulement de la théorie.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000163','00000000-0000-0000-0003-000000000040','I celebrate when my trainees exceed my own abilities.','Je célèbre quand mes stagiaires dépassent mes propres capacités.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000164','00000000-0000-0000-0003-000000000040','I have a leadership pipeline with people at various stages of development.','J''ai un pipeline de leadership avec des personnes à différents stades de développement.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000041','00000000-0000-0000-0002-000000000010','family-ministry-balance','Family & Ministry Balance','Family & Ministry Balance',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000165','00000000-0000-0000-0003-000000000041','My spouse and family feel valued, not sacrificed for ministry.','Mon conjoint et ma famille se sentent valorisés, pas sacrifiés pour le ministère.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000166','00000000-0000-0000-0003-000000000041','I take regular days off and vacations without guilt.','Je prends des jours de repos et des vacances réguliers sans culpabilité.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000167','00000000-0000-0000-0003-000000000041','I set boundaries on ministry demands to protect my family time.','Je fixe des limites aux exigences du ministère pour protéger mon temps familial.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000168','00000000-0000-0000-0003-000000000041','My children (if applicable) have a healthy view of ministry and the church.','Mes enfants (le cas échéant) ont une vision saine du ministère et de l''église.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000042','00000000-0000-0000-0002-000000000010','legacy-kingdom-impact','Legacy & Kingdom Impact','Legacy & Kingdom Impact',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000169','00000000-0000-0000-0003-000000000042','I think about the long-term impact of my ministry beyond my own lifetime.','Je pense à l''impact à long terme de mon ministère au-delà de ma propre vie.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000170','00000000-0000-0000-0003-000000000042','I invest in institutions (schools, programmes, networks) not just events.','J''investis dans les institutions (écoles, programmes, réseaux), pas seulement dans les événements.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000171','00000000-0000-0000-0003-000000000042','I measure success by transformation in people''s lives, not just activities.','Je mesure le succès par la transformation dans la vie des gens, pas seulement les activités.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000172','00000000-0000-0000-0003-000000000042','I am building a ministry that will thrive even after I''m gone.','Je construis un ministère qui prospérera même après mon départ.',4);
INSERT INTO tracks (id,slug,name_en,name_fr,description_en,description_fr,icon,color,sort_order) VALUES ('00000000-0000-0000-0001-000000000003','marriage','Marriage Coaching','Coaching Conjugal','Each spouse completes their intake individually across 5 Pillars and 20 relational dimensions. The platform analyses both sets of answers together.','Chaque conjoint complète l''évaluation individuellement à travers 5 Piliers et 20 dimensions relationnelles.','heart','#DB2777',3);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000011','00000000-0000-0000-0001-000000000003','personal-foundation','Personal Foundation','Personal Foundation','A healthy marriage starts with two healthy individuals','A healthy marriage starts with two healthy individuals',1);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000043','00000000-0000-0000-0002-000000000011','self-awareness','Self-Awareness','Self-Awareness',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000173','00000000-0000-0000-0003-000000000043','I understand my own emotional triggers and how they affect my spouse.','Je comprends mes propres déclencheurs émotionnels et comment ils affectent mon conjoint.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000174','00000000-0000-0000-0003-000000000043','I can identify patterns from my family of origin that I bring into my marriage.','Je peux identifier les schémas de ma famille d''origine que j''apporte dans mon mariage.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000175','00000000-0000-0000-0003-000000000043','I am honest with myself about my contribution to our marital challenges.','Je suis honnête avec moi-même sur ma contribution à nos défis conjugaux.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000176','00000000-0000-0000-0003-000000000043','I regularly reflect on my own growth areas rather than focusing on my spouse''s flaws.','Je réfléchis régulièrement à mes propres domaines de croissance plutôt que de me concentrer sur les défauts de mon conjoint.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000044','00000000-0000-0000-0002-000000000011','emotional-intelligence','Emotional Intelligence','Emotional Intelligence',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000177','00000000-0000-0000-0003-000000000044','I can manage my emotions during disagreements without shutting down or exploding.','Je peux gérer mes émotions pendant les désaccords sans me fermer ou exploser.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000178','00000000-0000-0000-0003-000000000044','I recognise when my spouse is struggling emotionally even if they don''t say it.','Je reconnais quand mon conjoint lutte émotionnellement même s''il ne le dit pas.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000179','00000000-0000-0000-0003-000000000044','I take responsibility for my emotional reactions rather than blaming my spouse.','Je prends la responsabilité de mes réactions émotionnelles plutôt que de blâmer mon conjoint.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000180','00000000-0000-0000-0003-000000000044','I can pause and regulate myself before responding in heated moments.','Je peux faire une pause et me réguler avant de répondre dans les moments tendus.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000045','00000000-0000-0000-0002-000000000011','personal-responsibility','Personal Responsibility','Personal Responsibility',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000181','00000000-0000-0000-0003-000000000045','I own my mistakes in the relationship without making excuses.','J''assume mes erreurs dans la relation sans faire d''excuses.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000182','00000000-0000-0000-0003-000000000045','I apologise sincerely when I am wrong, without adding ''but you also...''','Je m''excuse sincèrement quand j''ai tort, sans ajouter ''mais toi aussi...''',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000183','00000000-0000-0000-0003-000000000045','I work on myself consistently, not just when there''s a crisis.','Je travaille sur moi-même de manière constante, pas seulement en cas de crise.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000184','00000000-0000-0000-0003-000000000045','I seek personal growth (books, counselling, mentoring) for the sake of my marriage.','Je recherche une croissance personnelle (livres, accompagnement, mentorat) pour le bien de mon mariage.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000046','00000000-0000-0000-0002-000000000011','spiritual-value-alignment','Spiritual & Value Alignment','Spiritual & Value Alignment',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000185','00000000-0000-0000-0003-000000000046','My spouse and I share the same core values and life priorities.','Mon conjoint et moi partageons les mêmes valeurs fondamentales et priorités de vie.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000186','00000000-0000-0000-0003-000000000046','We pray together or engage in shared spiritual practices regularly.','Nous prions ensemble ou participons à des pratiques spirituelles partagées régulièrement.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000187','00000000-0000-0000-0003-000000000046','We agree on how faith influences our decisions as a couple.','Nous sommes d''accord sur la façon dont la foi influence nos décisions en tant que couple.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000188','00000000-0000-0000-0003-000000000046','We have discussed and aligned on our views about money, parenting, and purpose.','Nous avons discuté et aligné nos vues sur l''argent, l''éducation des enfants et notre mission.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000012','00000000-0000-0000-0001-000000000003','communication-connection','Communication & Connection','Communication & Connection','Most marriage problems are communication problems','Most marriage problems are communication problems',2);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000047','00000000-0000-0000-0002-000000000012','listening-empathy','Listening & Empathy','Listening & Empathy',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000189','00000000-0000-0000-0003-000000000047','I listen to my spouse without interrupting or planning my response.','J''écoute mon conjoint sans l''interrompre ou planifier ma réponse.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000190','00000000-0000-0000-0003-000000000047','I try to understand my spouse''s perspective even when I disagree.','J''essaie de comprendre la perspective de mon conjoint même quand je ne suis pas d''accord.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000191','00000000-0000-0000-0003-000000000047','My spouse would say I make them feel truly heard.','Mon conjoint dirait que je le fais se sentir véritablement écouté.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000192','00000000-0000-0000-0003-000000000047','I ask clarifying questions rather than assuming I know what my spouse means.','Je pose des questions de clarification plutôt que de supposer savoir ce que mon conjoint veut dire.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000048','00000000-0000-0000-0002-000000000012','conflict-resolution','Conflict Resolution','Conflict Resolution',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000193','00000000-0000-0000-0003-000000000048','We resolve conflicts without resorting to insults, stonewalling, or silent treatment.','Nous résolvons les conflits sans recourir aux insultes, au mutisme ou au traitement silencieux.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000194','00000000-0000-0000-0003-000000000048','We can disagree without it turning into a personal attack.','Nous pouvons être en désaccord sans que cela devienne une attaque personnelle.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000195','00000000-0000-0000-0003-000000000048','We have an agreed approach for handling arguments (time-outs, ground rules).','Nous avons une approche convenue pour gérer les disputes (temps morts, règles de base).',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000196','00000000-0000-0000-0003-000000000048','After a conflict, we reconcile and don''t let resentment build up.','Après un conflit, nous nous réconcilions et ne laissons pas le ressentiment s''accumuler.',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000197','00000000-0000-0000-0003-000000000048','We fight about the actual issue, not about past unresolved grievances.','Nous nous disputons sur le vrai sujet, pas sur des griefs passés non résolus.',5);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000049','00000000-0000-0000-0002-000000000012','emotional-intimacy','Emotional Intimacy','Emotional Intimacy',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000198','00000000-0000-0000-0003-000000000049','I feel safe being vulnerable and honest with my spouse.','Je me sens en sécurité pour être vulnérable et honnête avec mon conjoint.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000199','00000000-0000-0000-0003-000000000049','We share our fears, dreams, and inner thoughts with each other.','Nous partageons nos peurs, nos rêves et nos pensées profondes l''un avec l''autre.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000200','00000000-0000-0000-0003-000000000049','We have deep conversations beyond logistics and daily schedules.','Nous avons des conversations profondes au-delà de la logistique et des horaires quotidiens.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000201','00000000-0000-0000-0003-000000000049','I trust my spouse with my weaknesses and insecurities.','Je fais confiance à mon conjoint avec mes faiblesses et mes insécurités.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000050','00000000-0000-0000-0002-000000000012','appreciation-affirmation','Appreciation & Affirmation','Appreciation & Affirmation',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000202','00000000-0000-0000-0003-000000000050','I regularly express gratitude and appreciation to my spouse.','J''exprime régulièrement ma gratitude et mon appréciation à mon conjoint.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000203','00000000-0000-0000-0003-000000000050','I know my spouse''s love language and I speak it intentionally.','Je connais le langage d''amour de mon conjoint et je le parle intentionnellement.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000204','00000000-0000-0000-0003-000000000050','I compliment my spouse genuinely, not just when I want something.','Je complimente mon conjoint sincèrement, pas seulement quand je veux quelque chose.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000205','00000000-0000-0000-0003-000000000050','I celebrate my spouse''s achievements and encourage their growth.','Je célèbre les réussites de mon conjoint et encourage sa croissance.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000013','00000000-0000-0000-0001-000000000003','partnership-roles','Partnership & Roles','Partnership & Roles','Running a life together requires alignment','Running a life together requires alignment',3);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000051','00000000-0000-0000-0002-000000000013','decision-making-together','Decision-Making Together','Decision-Making Together',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000206','00000000-0000-0000-0003-000000000051','We make major decisions together as equal partners.','Nous prenons les décisions importantes ensemble en tant que partenaires égaux.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000207','00000000-0000-0000-0003-000000000051','Neither of us makes unilateral decisions that affect the other without consultation.','Aucun de nous ne prend de décisions unilatérales qui affectent l''autre sans consultation.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000208','00000000-0000-0000-0003-000000000051','We have a fair process for resolving disagreements on decisions.','Nous avons un processus équitable pour résoudre les désaccords sur les décisions.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000209','00000000-0000-0000-0003-000000000051','We respect each other''s areas of strength when dividing decision-making.','Nous respectons les domaines de force de chacun dans la répartition des décisions.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000052','00000000-0000-0000-0002-000000000013','financial-partnership','Financial Partnership','Financial Partnership',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000210','00000000-0000-0000-0003-000000000052','We have open, honest conversations about money without shame or blame.','Nous avons des conversations ouvertes et honnêtes sur l''argent sans honte ni blâme.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000211','00000000-0000-0000-0003-000000000052','We have a shared budget or financial plan that we both agree on.','Nous avons un budget ou un plan financier commun sur lequel nous sommes d''accord.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000212','00000000-0000-0000-0003-000000000052','We make financial decisions together rather than hiding spending.','Nous prenons les décisions financières ensemble plutôt que de cacher des dépenses.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000213','00000000-0000-0000-0003-000000000052','We are aligned on our approach to saving, giving, and debt.','Nous sommes alignés sur notre approche de l''épargne, des dons et de la dette.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000053','00000000-0000-0000-0002-000000000013','household-parenting-alignment','Household & Parenting Alignment','Household & Parenting Alignment',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000214','00000000-0000-0000-0003-000000000053','We share household responsibilities in a way that feels fair to both of us.','Nous partageons les responsabilités ménagères d''une manière qui semble juste pour nous deux.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000215','00000000-0000-0000-0003-000000000053','We agree on our parenting approach and present a united front to our children.','Nous sommes d''accord sur notre approche parentale et présentons un front uni à nos enfants.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000216','00000000-0000-0000-0003-000000000053','We discuss and adjust roles as our family situation changes.','Nous discutons et ajustons les rôles au fur et à mesure que notre situation familiale évolue.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000217','00000000-0000-0000-0003-000000000053','Neither of us carries a disproportionate burden without acknowledgment.','Aucun de nous ne porte un fardeau disproportionné sans reconnaissance.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000054','00000000-0000-0000-0002-000000000013','extended-family-boundaries','Extended Family Boundaries','Extended Family Boundaries',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000218','00000000-0000-0000-0003-000000000054','We have clear, agreed boundaries with our extended families.','Nous avons des limites claires et convenues avec nos familles élargies.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000219','00000000-0000-0000-0003-000000000054','My spouse feels prioritised over my parents and siblings.','Mon conjoint se sent prioritaire par rapport à mes parents et frères et sœurs.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000220','00000000-0000-0000-0003-000000000054','We handle in-law conflicts as a team rather than siding with our own families.','Nous gérons les conflits avec la belle-famille en équipe plutôt que de prendre le parti de notre propre famille.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000221','00000000-0000-0000-0003-000000000054','We have discussed how much influence extended family has on our decisions.','Nous avons discuté de l''influence que la famille élargie a sur nos décisions.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000014','00000000-0000-0000-0001-000000000003','intimacy-sexuality','Intimacy & Sexuality','Intimacy & Sexuality','The dimension most couples avoid but desperately need','The dimension most couples avoid but desperately need',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000055','00000000-0000-0000-0002-000000000014','physical-intimacy','Physical Intimacy','Physical Intimacy',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000222','00000000-0000-0000-0003-000000000055','I am satisfied with the frequency and quality of our physical intimacy.','Je suis satisfait de la fréquence et de la qualité de notre intimité physique.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000223','00000000-0000-0000-0003-000000000055','We are both comfortable initiating physical affection.','Nous sommes tous deux à l''aise pour initier l''affection physique.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000224','00000000-0000-0000-0003-000000000055','Physical intimacy in our marriage goes beyond just sexual intercourse.','L''intimité physique dans notre mariage va au-delà des rapports sexuels.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000225','00000000-0000-0000-0003-000000000055','We make time for physical connection even during busy or stressful seasons.','Nous faisons du temps pour la connexion physique même pendant les périodes occupées ou stressantes.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000056','00000000-0000-0000-0002-000000000014','sexual-communication','Sexual Communication','Sexual Communication',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000226','00000000-0000-0000-0003-000000000056','We can talk openly about our sexual needs without embarrassment.','Nous pouvons parler ouvertement de nos besoins sexuels sans embarras.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000227','00000000-0000-0000-0003-000000000056','I feel comfortable expressing what I enjoy and what I don''t.','Je me sens à l''aise pour exprimer ce que j''apprécie et ce que je n''apprécie pas.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000228','00000000-0000-0000-0003-000000000056','We address sexual concerns or dissatisfaction constructively.','Nous abordons les préoccupations ou insatisfactions sexuelles de manière constructive.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000229','00000000-0000-0000-0003-000000000056','Neither of us uses sex as a weapon, bargaining tool, or punishment.','Aucun de nous n''utilise le sexe comme arme, monnaie d''échange ou punition.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000057','00000000-0000-0000-0002-000000000014','romance-intentionality','Romance & Intentionality','Romance & Intentionality',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000230','00000000-0000-0000-0003-000000000057','We go on regular dates or create intentional couple time.','Nous sortons régulièrement en couple ou créons du temps intentionnel à deux.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000231','00000000-0000-0000-0003-000000000057','We still flirt, surprise each other, and keep romance alive.','Nous flirtons encore, nous surprenons mutuellement et gardons la romance vivante.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000232','00000000-0000-0000-0003-000000000057','I put effort into being attractive and attentive to my spouse.','Je fais des efforts pour être attrayant et attentionné envers mon conjoint.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000233','00000000-0000-0000-0003-000000000057','We have fun together — our relationship isn''t all responsibilities and problems.','Nous nous amusons ensemble — notre relation n''est pas que responsabilités et problèmes.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000058','00000000-0000-0000-0002-000000000014','trust-fidelity','Trust & Fidelity','Trust & Fidelity',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000234','00000000-0000-0000-0003-000000000058','I trust my spouse completely with their friendships and interactions.','Je fais entièrement confiance à mon conjoint concernant ses amitiés et interactions.',1);
