INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000236','00000000-0000-0000-0003-000000000058','There are no secrets between us that would damage our relationship if revealed.','Il n''y a pas de secrets entre nous qui endommageraient notre relation s''ils étaient révélés.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000237','00000000-0000-0000-0003-000000000058','We protect our marriage by being transparent about where we go and who we see.','Nous protégeons notre mariage en étant transparents sur nos déplacements et fréquentations.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000015','00000000-0000-0000-0001-000000000003','growth-legacy','Growth & Legacy','Growth & Legacy','A marriage with no vision drifts','A marriage with no vision drifts',5);
