INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000238','00000000-0000-0000-0003-000000000059','We have a shared vision for where our marriage and family is heading.','Nous avons une vision commune de la direction de notre mariage et de notre famille.',1);
