INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000241','00000000-0000-0000-0003-000000000059','We dream together about the future rather than just surviving the present.','Nous rêvons ensemble de l''avenir plutôt que de simplement survivre au présent.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000060','00000000-0000-0000-0002-000000000015','crisis-resilience','Crisis Resilience','Crisis Resilience',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000242','00000000-0000-0000-0003-000000000060','We have navigated a major crisis together and come out stronger.','Nous avons traversé une crise majeure ensemble et en sommes sortis plus forts.',1);
