INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000062','00000000-0000-0000-0002-000000000015','legacy-impact','Legacy & Impact','Legacy & Impact',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000250','00000000-0000-0000-0003-000000000062','We are intentional about the example we set for our children.','Nous sommes intentionnels quant à l''exemple que nous donnons à nos enfants.',1);
