INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000254','00000000-0000-0000-0003-000000000063','I see obstacles as opportunities rather than reasons to quit.','Je vois les obstacles comme des opportunités plutôt que des raisons d''abandonner.',1);
