INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000017','00000000-0000-0000-0001-000000000004','business-foundations','Business Foundations','Business Foundations','The brutal truth about whether your business works','The brutal truth about whether your business works',2);
