INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000085','00000000-0000-0000-0002-000000000021','personality-strengths','Personality & Strengths','Personality & Strengths',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000346','00000000-0000-0000-0003-000000000085','I know my personality type and understand how it affects my behaviour.','Je connais mon type de personnalité et comprends comment il affecte mon comportement.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000347','00000000-0000-0000-0003-000000000085','I can name my top strengths and I actively use them in my daily life.','Je peux nommer mes principales forces et je les utilise activement dans ma vie quotidienne.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000348','00000000-0000-0000-0003-000000000085','I understand my weaknesses and manage them rather than pretending they don''t exist.','Je comprends mes faiblesses et les gère plutôt que de prétendre qu''elles n''existent pas.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000349','00000000-0000-0000-0003-000000000085','I have taken at least one formal assessment (personality, strengths, or gifts).','J''ai passé au moins un test formel (personnalité, forces ou dons).',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000086','00000000-0000-0000-0002-000000000021','values-beliefs','Values & Beliefs','Values & Beliefs',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000350','00000000-0000-0000-0003-000000000086','I can clearly articulate my top 5 core values.','Je peux clairement articuler mes 5 valeurs fondamentales.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000351','00000000-0000-0000-0003-000000000086','My daily decisions and actions are aligned with my stated values.','Mes décisions et actions quotidiennes sont alignées avec mes valeurs déclarées.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000352','00000000-0000-0000-0003-000000000086','I have examined my beliefs critically rather than simply inheriting them.','J''ai examiné mes croyances de manière critique plutôt que de simplement les hériter.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000353','00000000-0000-0000-0003-000000000086','When my actions conflict with my values, I notice and correct course.','Quand mes actions entrent en conflit avec mes valeurs, je le remarque et je corrige le cap.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000087','00000000-0000-0000-0002-000000000021','purpose-calling','Purpose & Calling','Purpose & Calling',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000354','00000000-0000-0000-0003-000000000087','I have a sense of purpose — I know why I''m here.','J''ai un sens du but — je sais pourquoi je suis ici.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000355','00000000-0000-0000-0003-000000000087','I can connect my daily activities to a bigger picture or mission.','Je peux relier mes activités quotidiennes à une mission ou un objectif plus grand.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000356','00000000-0000-0000-0003-000000000087','I feel energised and alive when I am operating in my purpose.','Je me sens énergisé et vivant quand j''opère dans mon but.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000357','00000000-0000-0000-0003-000000000087','I am actively pursuing my calling, not just waiting for it to find me.','Je poursuis activement mon appel, pas seulement en attendant qu''il me trouve.',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000358','00000000-0000-0000-0003-000000000087','I can distinguish between what I''m good at and what I''m called to.','Je peux distinguer entre ce dans quoi je suis doué et ce pour quoi je suis appelé.',5);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000022','00000000-0000-0000-0001-000000000005','inner-healing','Inner Healing','Inner Healing','You can''t build a new life on unhealed foundations','You can''t build a new life on unhealed foundations',2);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000088','00000000-0000-0000-0002-000000000022','identifying-past-wounds','Identifying Past Wounds','Identifying Past Wounds',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000359','00000000-0000-0000-0003-000000000088','I am aware of specific past experiences that still affect me emotionally today.','Je suis conscient d''expériences passées spécifiques qui m''affectent encore émotionnellement aujourd''hui.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000360','00000000-0000-0000-0003-000000000088','I can identify patterns in my life (relationships, reactions, fears) linked to past pain.','Je peux identifier des schémas dans ma vie (relations, réactions, peurs) liés à des douleurs passées.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000361','00000000-0000-0000-0003-000000000088','I have reflected on how my childhood and upbringing shaped my current behaviours.','J''ai réfléchi à la façon dont mon enfance et mon éducation ont façonné mes comportements actuels.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000362','00000000-0000-0000-0003-000000000088','I recognise when I am reacting from a wounded place rather than a whole place.','Je reconnais quand je réagis d''un lieu blessé plutôt que d''un lieu sain.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000089','00000000-0000-0000-0002-000000000022','forgiveness-release','Forgiveness & Release','Forgiveness & Release',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000363','00000000-0000-0000-0003-000000000089','I have forgiven those who have hurt me, even if I haven''t forgotten.','J''ai pardonné à ceux qui m''ont blessé, même si je n''ai pas oublié.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000364','00000000-0000-0000-0003-000000000089','I do not carry active bitterness or resentment toward specific people.','Je ne porte pas d''amertume ou de ressentiment actif envers des personnes spécifiques.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000365','00000000-0000-0000-0003-000000000089','I have released the need for revenge, vindication, or an apology I may never receive.','J''ai renoncé au besoin de vengeance, de justification ou d''excuses que je ne recevrai peut-être jamais.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000366','00000000-0000-0000-0003-000000000089','I practise forgiveness as a choice, not a feeling.','Je pratique le pardon comme un choix, pas un sentiment.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000090','00000000-0000-0000-0002-000000000022','overcoming-shame-rejection','Overcoming Shame & Rejection','Overcoming Shame & Rejection',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000367','00000000-0000-0000-0003-000000000090','I do not carry a deep sense of shame about who I am.','Je ne porte pas un sentiment profond de honte sur qui je suis.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000368','00000000-0000-0000-0003-000000000090','Rejection from others does not devastate me or define my self-image.','Le rejet des autres ne me dévaste pas et ne définit pas mon image de moi.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000369','00000000-0000-0000-0003-000000000090','I can distinguish between guilt (I did something wrong) and shame (I am something wrong).','Je peux distinguer entre la culpabilité (j''ai fait quelque chose de mal) et la honte (je suis quelque chose de mal).',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000370','00000000-0000-0000-0003-000000000090','I have experienced healing or freedom from specific shame-based narratives.','J''ai vécu une guérison ou une libération de récits basés sur la honte.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000091','00000000-0000-0000-0002-000000000022','breaking-unhealthy-patterns','Breaking Unhealthy Patterns','Breaking Unhealthy Patterns',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000371','00000000-0000-0000-0003-000000000091','I have identified recurring negative patterns in my life (addictions, toxic relationships, self-sabotage).','J''ai identifié des schémas négatifs récurrents dans ma vie (addictions, relations toxiques, auto-sabotage).',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000372','00000000-0000-0000-0003-000000000091','I am actively working to break at least one destructive cycle.','Je travaille activement à briser au moins un cycle destructeur.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000373','00000000-0000-0000-0003-000000000091','I understand the root causes behind my unhealthy coping mechanisms.','Je comprends les causes profondes de mes mécanismes d''adaptation malsains.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000374','00000000-0000-0000-0003-000000000091','I have replaced at least one unhealthy habit with a healthy alternative.','J''ai remplacé au moins une habitude malsaine par une alternative saine.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000092','00000000-0000-0000-0002-000000000022','restoration-wholeness','Restoration & Wholeness','Restoration & Wholeness',5);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000375','00000000-0000-0000-0003-000000000092','I feel like I am moving from surviving to thriving.','Je sens que je passe de la survie à l''épanouissement.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000376','00000000-0000-0000-0003-000000000092','I experience inner peace and emotional stability most of the time.','J''éprouve une paix intérieure et une stabilité émotionnelle la plupart du temps.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000377','00000000-0000-0000-0003-000000000092','I can talk about my past without being overwhelmed by it.','Je peux parler de mon passé sans en être submergé.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000378','00000000-0000-0000-0003-000000000092','I am becoming the person I was created to be — healed, whole, and free.','Je deviens la personne que j''ai été créé pour être — guéri, entier et libre.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000023','00000000-0000-0000-0001-000000000005','whole-person-health','Whole-Person Health','Whole-Person Health','An integrated system — one affects all','An integrated system — one affects all',3);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000093','00000000-0000-0000-0002-000000000023','spiritual-life','Spiritual Life','Spiritual Life',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000379','00000000-0000-0000-0003-000000000093','I have a consistent spiritual practice (prayer, meditation, worship) that nourishes me.','J''ai une pratique spirituelle cohérente (prière, méditation, adoration) qui me nourrit.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000380','00000000-0000-0000-0003-000000000093','I experience genuine peace and connection in my spiritual life.','J''éprouve une paix et une connexion véritables dans ma vie spirituelle.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000381','00000000-0000-0000-0003-000000000093','My faith positively influences my decisions and relationships.','Ma foi influence positivement mes décisions et mes relations.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000382','00000000-0000-0000-0003-000000000093','I am growing spiritually — I am not stagnant or going through the motions.','Je grandis spirituellement — je ne stagne pas et ne fais pas que suivre les mouvements.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000094','00000000-0000-0000-0002-000000000023','emotional-health','Emotional Health','Emotional Health',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000383','00000000-0000-0000-0003-000000000094','I am aware of my emotions and can name what I''m feeling in the moment.','Je suis conscient de mes émotions et peux nommer ce que je ressens sur le moment.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000384','00000000-0000-0000-0003-000000000094','I process difficult emotions rather than suppressing or exploding with them.','Je traite les émotions difficiles plutôt que de les supprimer ou d''exploser avec elles.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000385','00000000-0000-0000-0003-000000000094','I have healthy outlets for stress, sadness, and frustration.','J''ai des exutoires sains pour le stress, la tristesse et la frustration.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000386','00000000-0000-0000-0003-000000000094','I can experience joy, gratitude, and contentment regularly.','Je peux éprouver de la joie, de la gratitude et du contentement régulièrement.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000095','00000000-0000-0000-0002-000000000023','mental-wellness','Mental Wellness','Mental Wellness',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000387','00000000-0000-0000-0003-000000000095','My thought patterns are generally healthy and constructive.','Mes schémas de pensée sont généralement sains et constructifs.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000388','00000000-0000-0000-0003-000000000095','I manage anxiety and worry effectively rather than being controlled by them.','Je gère l''anxiété et l''inquiétude efficacement plutôt que d''être contrôlé par elles.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000389','00000000-0000-0000-0003-000000000095','I can focus and think clearly without chronic mental fog or overwhelm.','Je peux me concentrer et penser clairement sans brouillard mental chronique ou surcharge.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000390','00000000-0000-0000-0003-000000000095','I would seek professional help if my mental health needed it, without stigma.','Je chercherais une aide professionnelle si ma santé mentale en avait besoin, sans stigmate.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000096','00000000-0000-0000-0002-000000000023','physical-health','Physical Health','Physical Health',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000391','00000000-0000-0000-0003-000000000096','I exercise or move my body regularly as part of my lifestyle.','Je fais de l''exercice ou bouge mon corps régulièrement comme partie de mon style de vie.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000392','00000000-0000-0000-0003-000000000096','I eat in a way that nourishes and energises me.','Je mange d''une manière qui me nourrit et m''énergise.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000393','00000000-0000-0000-0003-000000000096','I get enough quality sleep most nights.','J''ai un sommeil de qualité suffisant la plupart des nuits.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000394','00000000-0000-0000-0003-000000000096','I take care of my physical health proactively — checkups, rest, hydration.','Je prends soin de ma santé physique de manière proactive — bilans, repos, hydratation.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000024','00000000-0000-0000-0001-000000000005','relational-intelligence','Relational Intelligence','Relational Intelligence','No one grows alone','No one grows alone',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000097','00000000-0000-0000-0002-000000000024','communication-skills','Communication Skills','Communication Skills',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000395','00000000-0000-0000-0003-000000000097','I express myself clearly and honestly without being hurtful.','Je m''exprime clairement et honnêtement sans être blessant.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000396','00000000-0000-0000-0003-000000000097','I am a good listener — I hear people out before responding.','Je suis un bon auditeur — j''écoute les gens avant de répondre.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000397','00000000-0000-0000-0003-000000000097','I adapt my communication style depending on who I''m speaking with.','J''adapte mon style de communication selon la personne à qui je parle.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000398','00000000-0000-0000-0003-000000000097','I can have difficult conversations without avoiding or attacking.','Je peux avoir des conversations difficiles sans éviter ou attaquer.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000098','00000000-0000-0000-0002-000000000024','conflict-management','Conflict Management','Conflict Management',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000399','00000000-0000-0000-0003-000000000098','I address conflict directly rather than avoiding or suppressing it.','J''aborde les conflits directement plutôt que de les éviter ou les supprimer.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000400','00000000-0000-0000-0003-000000000098','I can disagree with someone without damaging the relationship.','Je peux être en désaccord avec quelqu''un sans endommager la relation.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000401','00000000-0000-0000-0003-000000000098','I seek understanding before trying to be understood in disagreements.','Je cherche à comprendre avant d''essayer d''être compris dans les désaccords.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000402','00000000-0000-0000-0003-000000000098','I don''t hold grudges — I resolve issues and move forward.','Je ne garde pas rancune — je résous les problèmes et passe à autre chose.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000099','00000000-0000-0000-0002-000000000024','boundaries','Boundaries','Boundaries',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000403','00000000-0000-0000-0003-000000000099','I can say ''no'' without guilt when something doesn''t align with my priorities.','Je peux dire ''non'' sans culpabilité quand quelque chose ne correspond pas à mes priorités.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000404','00000000-0000-0000-0003-000000000099','I know the difference between being kind and being a pushover.','Je connais la différence entre être gentil et être un paillasson.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000405','00000000-0000-0000-0003-000000000099','I have healthy boundaries with family, friends, and work.','J''ai des limites saines avec la famille, les amis et le travail.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000406','00000000-0000-0000-0003-000000000099','I respect other people''s boundaries as much as I expect them to respect mine.','Je respecte les limites des autres autant que j''attends qu''ils respectent les miennes.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000100','00000000-0000-0000-0002-000000000024','community-belonging','Community & Belonging','Community & Belonging',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000407','00000000-0000-0000-0003-000000000100','I have meaningful relationships where I am known and loved.','J''ai des relations significatives où je suis connu et aimé.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000408','00000000-0000-0000-0003-000000000100','I invest intentionally in building and maintaining friendships.','J''investis intentionnellement dans la construction et le maintien d''amitiés.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000409','00000000-0000-0000-0003-000000000100','I belong to a community (church, group, network) that supports my growth.','J''appartiens à une communauté (église, groupe, réseau) qui soutient ma croissance.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000410','00000000-0000-0000-0003-000000000100','I don''t isolate myself — I allow others to speak into my life.','Je ne m''isole pas — je permets aux autres de parler dans ma vie.',4);
INSERT INTO pillars (id,track_id,slug,name_en,name_fr,description_en,description_fr,sort_order) VALUES ('00000000-0000-0000-0002-000000000025','00000000-0000-0000-0001-000000000005','purpose-productivity','Purpose & Productivity','Purpose & Productivity','From self-improvement to contribution','From self-improvement to contribution',5);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000101','00000000-0000-0000-0002-000000000025','goal-setting-planning','Goal Setting & Planning','Goal Setting & Planning',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000411','00000000-0000-0000-0003-000000000101','I set clear, specific goals for different areas of my life.','Je fixe des objectifs clairs et spécifiques pour différents domaines de ma vie.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000412','00000000-0000-0000-0003-000000000101','I break big goals into small, actionable steps with timelines.','Je décompose les grands objectifs en petites étapes actionnables avec des échéances.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000413','00000000-0000-0000-0003-000000000101','I review my goals regularly and track my progress.','Je révise mes objectifs régulièrement et suis mes progrès.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000414','00000000-0000-0000-0003-000000000101','I adjust my goals when circumstances change rather than abandoning them.','J''ajuste mes objectifs quand les circonstances changent plutôt que de les abandonner.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000102','00000000-0000-0000-0002-000000000025','time-management-discipline','Time Management & Discipline','Time Management & Discipline',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000415','00000000-0000-0000-0003-000000000102','I manage my time intentionally rather than just reacting to what comes up.','Je gère mon temps intentionnellement plutôt que de simplement réagir à ce qui arrive.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000416','00000000-0000-0000-0003-000000000102','I prioritise what''s important over what''s urgent.','Je priorise ce qui est important sur ce qui est urgent.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000417','00000000-0000-0000-0003-000000000102','I have daily routines and habits that support my goals.','J''ai des routines et habitudes quotidiennes qui soutiennent mes objectifs.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000418','00000000-0000-0000-0003-000000000102','I avoid chronic procrastination and time-wasting activities.','J''évite la procrastination chronique et les activités qui gaspillent du temps.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000103','00000000-0000-0000-0002-000000000025','financial-literacy','Financial Literacy','Financial Literacy',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000419','00000000-0000-0000-0003-000000000103','I have a personal budget and I generally stick to it.','J''ai un budget personnel et je le respecte généralement.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000420','00000000-0000-0000-0003-000000000103','I understand the basics of saving, investing, and managing debt.','Je comprends les bases de l''épargne, de l''investissement et de la gestion de la dette.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000421','00000000-0000-0000-0003-000000000103','I make financial decisions based on planning, not impulse.','Je prends des décisions financières basées sur la planification, pas l''impulsion.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000422','00000000-0000-0000-0003-000000000103','I am building financial stability rather than living paycheck to paycheck.','Je construis une stabilité financière plutôt que de vivre au jour le jour.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000104','00000000-0000-0000-0002-000000000025','career-vocation-clarity','Career & Vocation Clarity','Career & Vocation Clarity',4);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000423','00000000-0000-0000-0003-000000000104','I am clear on what kind of work energises me and fits my strengths.','Je suis clair sur le type de travail qui m''énergise et correspond à mes forces.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000424','00000000-0000-0000-0003-000000000104','I am actively developing skills that will advance my career or calling.','Je développe activement des compétences qui feront avancer ma carrière ou mon appel.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000425','00000000-0000-0000-0003-000000000104','I am in the right lane professionally — or I have a plan to get there.','Je suis dans la bonne voie professionnellement — ou j''ai un plan pour y arriver.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000426','00000000-0000-0000-0003-000000000104','I don''t just work for money — I work for meaning and contribution.','Je ne travaille pas seulement pour l''argent — je travaille pour le sens et la contribution.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000105','00000000-0000-0000-0002-000000000025','leadership-readiness-legacy','Leadership Readiness & Legacy','Leadership Readiness & Legacy',5);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000427','00000000-0000-0000-0003-000000000105','I am ready and willing to lead others, not just manage myself.','Je suis prêt et disposé à diriger les autres, pas seulement à me gérer moi-même.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000428','00000000-0000-0000-0003-000000000105','I think about the impact I want to have on the world around me.','Je pense à l''impact que je veux avoir sur le monde autour de moi.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000429','00000000-0000-0000-0003-000000000105','I serve and give back to my community or church regularly.','Je sers et redonne à ma communauté ou mon église régulièrement.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000430','00000000-0000-0000-0003-000000000105','I live with the end in mind — my daily choices reflect my long-term vision.','Je vis avec la fin en tête — mes choix quotidiens reflètent ma vision à long terme.',4);
INSERT INTO sub_domains (id,pillar_id,slug,name_en,name_fr,sort_order) VALUES ('00000000-0000-0000-0003-000000000106','00000000-0000-0000-0002-000000000025','learning-skill-development','Learning & Skill Development','Learning & Skill Development',6);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000431','00000000-0000-0000-0003-000000000106','I am actively learning new skills relevant to my goals and calling.','J''apprends activement de nouvelles compétences pertinentes pour mes objectifs et mon appel.',1);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000432','00000000-0000-0000-0003-000000000106','I read, listen to podcasts, or take courses regularly to grow.','Je lis, écoute des podcasts ou suis des cours régulièrement pour grandir.',2);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000433','00000000-0000-0000-0003-000000000106','I invest time and money in my own development.','J''investis du temps et de l''argent dans mon propre développement.',3);
INSERT INTO questions (id,sub_domain_id,text_en,text_fr,sort_order) VALUES ('00000000-0000-0000-0004-000000000434','00000000-0000-0000-0003-000000000106','I apply what I learn rather than just consuming information passively.','J''applique ce que j''apprends plutôt que de simplement consommer de l''information passivement.',4);
